```julia
function my_sinh(x::num) where {num <: Number}
	y=exp(x)
	return (y-inv(y))/2
end
function my_cosh(x::num) where {num <: Number}
	y=exp(x)
	return (y+inv(y))/2
end
function my_tanh(x::num) where {num <: Number}
	y=exp(2*x)
	return (y-1)/(y+1)
end
using BenchmarkTools

x=randn(10_000);
@btime my_sinh.($x);
@btime sinh.($x);
@btime my_cosh.($x);
@btime cosh.($x);
@btime my_tanh.($x);
@btime tanh.($x);
```
I get 2X for sinh and tanh and X1.5 for cosh for Float64. In case of Float32 this doesn't happen.
